SELECT

FROM M_USER

    DELETED_AT IS NULL

        AND USERNAME LIKE CONCAT('%', #{username}, '%')


        AND EMAIL LIKE CONCAT('%', #{email}, '%')


        AND STATUS = #{status}


        AND ACCOUNT_LOCKED = #{locked}


        AND TENANT_ID = #{tenantId}


ORDER BY ID DESC
LIMIT #{limit} OFFSET #{offset}

SELECT
    COUNT(1)
FROM M_USER

    DELETED_AT IS NULL

        AND USERNAME LIKE CONCAT('%', #{username}, '%')


        AND EMAIL LIKE CONCAT('%', #{email}, '%')


        AND STATUS = #{status}


        AND ACCOUNT_LOCKED = #{locked}


        AND TENANT_ID = #{tenantId}
